//-------------------------------------------------------------------------
// Enable/Disable
//-------------------------------------------------------------------------
scwin.f_firstSetting = function () {
  $c.gus.cfDisableKeyData($p);

  // 기본정보 항목
  $c.gus.cfDisableObjects($p, [rd_wrkClsCd, acb_deptCd, ed_applyDt, ed_vehclNo, ed_drcrNo, lc_cancelCd, lc_possessCd, lc_vehclTypeCd, ed_maxPayloadCd, ed_releaseYear]);

  // 자동차보험 항목
  //cfDisableObjects([ed_carInsuranceShortStdDt, ed_carInsuranceShortEndDt, img_carInsuranceShortStdDt, img_carInsuranceShortEndDt]); 
  $c.gus.cfDisableObjects($p, [udc_carInsuranceYear]);
  $c.gus.cfDisableObjects($p, [lc_objectLimitCd, lc_driverAge]);
  $c.gus.cfDisableObjects($p, [cbx_selfVehclYn, udc_selfVehcl]);
  $c.gus.cfDisableObjects($p, [cbx_sfdmgVehclYn, udc_sfdmgVehcl]);

  // 적재물보험 항목
  //cfDisableObjects([ed_luggageInsuranceShortStdDt, ed_luggageInsuranceShortEndDt, img_luggageInsuranceShortStdDt, img_luggageInsuranceShortEndDt]); 
  $c.gus.cfDisableObjects($p, [udc_luggageInsuranceYear]);
  $c.gus.cfDisableObjects($p, [lc_guaranteeLimitCd]);
  $c.gus.cfDisableObjects($p, [cbx_glassYn, udc_glass]);
  $c.gus.cfDisableObjects($p, [cbx_frizYn, udc_friz]);
  //cfDisableObjects([chb_umbrellaPolicyYn, ed_umbrellaPolicyStdDt, ed_umbrellaPolicyEndDt, img_umbrellaPolicyStdDt, img_umbrellaPolicyEndDt]);

  // 버튼 항목
  $c.gus.cfDisableObjects($p, [btn_create, btn_update, btn_cancel, btn_save]);

  // 산재보험 항목
  $c.gus.cfDisableObjects($p, [udc_indDistr, ed_indDistrDrvNm, ed_indDistrBirthDt, rd_indDistrWrkClsCd, lc_indDistrSndTypeCd]);
};

//-------------------------------------------------------------------------
// Enable
//-------------------------------------------------------------------------
scwin.f_enableSetting = function () {
  // 기본정보
  $c.gus.cfEnableObjects($p, [acb_deptCd, ed_vehclNo, ed_drcrNo, lc_possessCd, lc_vehclTypeCd, ed_maxPayloadCd, ed_releaseYear]);

  // 자동차 보험
  //cfEnableObjects([ed_carInsuranceShortStdDt, ed_carInsuranceShortEndDt, img_carInsuranceShortStdDt, img_carInsuranceShortEndDt]); 
  $c.gus.cfEnableObjects($p, [udc_carInsuranceYear]);
  $c.gus.cfEnableObjects($p, [lc_objectLimitCd, lc_driverAge, cbx_selfVehclYn, cbx_sfdmgVehclYn]);

  // 적재물 보험
  //cfEnableObjects([ed_luggageInsuranceShortStdDt, ed_luggageInsuranceShortEndDt, img_luggageInsuranceShortStdDt, img_luggageInsuranceShortEndDt]); 
  $c.gus.cfEnableObjects($p, [udc_luggageInsuranceYear]);
  $c.gus.cfEnableObjects($p, [lc_guaranteeLimitCd, cbx_glassYn, cbx_frizYn]); //, chb_umbrellaPolicyYn]); 

  scwin.f_checkSelfVehclYn();
  scwin.f_checkSfdmgVehclYn();
  scwin.f_checkGlassYn();
  scwin.f_checkFrizYn();
  //scwin.f_checkUmbrellaPolicyYn();

  // 산재보험 항목
  $c.gus.cfEnableObjects($p, [udc_indDistr, ed_indDistrDrvNm, ed_indDistrBirthDt, rd_indDistrWrkClsCd, lc_indDistrSndTypeCd]);
};

//-------------------------------------------------------------------------
// onloadSetting
//-------------------------------------------------------------------------
scwin.f_onloadSetting = function () {
  scwin.f_firstSetting();
  let row = ds_vehclInsuranceMgnt.getRowPosition();
  if (row < 0) return;
  let chkWrkClsCd = ds_vehclInsuranceMgnt.getCellData(row, "wrkClsCd");
  let chkApprvReqNo = ds_vehclInsuranceMgnt.getCellData(row, "apprvReqNo");
  let chkApprvStsCd = ds_vehclInsuranceMgnt.getCellData(row, "apprvStsCd");
  if (chkApprvReqNo == '') {
    // 전자결재 올리지 않은 상태 (수정이 가능 해야함)
    $c.gus.cfEnableObjects($p, [btn_create, btn_update]);
  } else {
    if (chkApprvStsCd == '05' || chkApprvStsCd == '03' || chkApprvStsCd == '06') {
      // 전자결재 최종완결 상태와 반려 상태 (수정이 가능 해야함)
      $c.gus.cfEnableObjects($p, [btn_create, btn_update]);
    } else {
      // 전자결재는 상신했음 ~ 나머지 상태들 (신규만 가능)
      $c.gus.cfEnableObjects($p, [btn_create]);
    }
  }
  if (chkWrkClsCd == '02' && chkApprvStsCd == '01') {
    if (scwin.pPorteYn == '') {
      $c.gus.cfEnableObjects($p, [btn_create, btn_update]);
    }
  }
};

//-------------------------------------------------------------------------
// 신규 버튼 클릭시
//------------------------------------------------------------------------- 
scwin.f_Create = function () {
  let newRow = ds_vehclInsuranceMgnt.insertRow();
  gr_vehclInsuranceMgnt.setFocusedCell(newRow, "wrkClsCd");
  ds_vehclInsuranceMgnt.setCellData(newRow, "wrkClsCd", '01'); // 작업구분
  ds_vehclInsuranceMgnt.setCellData(newRow, "deptCd", scwin.gv_loabranCd); // 소속지사
  ds_vehclInsuranceMgnt.setCellData(newRow, "applyDt", $c.date.getServerDateTime($p, "yyyyMMdd")); // 신청일자

  scwin.f_enableSetting();
  $c.gus.cfEnableObjects($p, [rd_wrkClsCd, btn_cancel, btn_save]);
  $c.gus.cfDisableObjects($p, [btn_create, btn_update]);
};

//-------------------------------------------------------------------------
// 수정 버튼 클릭시
//-------------------------------------------------------------------------             
scwin.f_Update = function () {
  $c.gus.cfDisableObjects($p, [btn_create, btn_update]);
  $c.gus.cfEnableObjects($p, [rd_wrkClsCd, btn_cancel, btn_save]);
  rd_wrkClsCd.focus();
  let row = ds_vehclInsuranceMgnt.getRowPosition();
  ds_vehclInsuranceMgnt.setCellData(row, "applyDt", $c.date.getServerDateTime($p, "yyyyMMdd")); // 신청일자

  let chkWrkClsCd = ds_vehclInsuranceMgnt.getCellData(row, "wrkClsCd");
  if (chkWrkClsCd == '01') {
    // 가입 상태인 경우 모든 메뉴 수정 가능
    scwin.f_enableSetting();
  } else if (chkWrkClsCd == '02') {
    // 변경 상태인 경우 [기본정보: 소속지사, 차량번호, 차대번호, 최대적재량, 차량년식, 소유구분, 차량형식]
    // [자동차보험정보: 자차, 자손, 운전자연령, 대물한도],[적재물보험정보: 유리특약, 냉동특약, 보상한도] 수정가능
    scwin.f_enableSetting();
    //$c.gus.cfDisableObjects([ed_maxPayloadCd, ed_releaseYear]);
  } else if (chkWrkClsCd == '03') {
    // 대차를 선택 하는 경우 차대번호, 최대적재량, 차량년식, 소속지사, 소유구분만 수정 가능
    $c.gus.cfEnableObjects($p, [ed_drcrNo, ed_maxPayloadCd, ed_releaseYear, acb_deptCd, lc_possessCd]);
  } else if (chkWrkClsCd == '04') {
    // 갱신 상태인 경우 모든 메뉴 수정 가능
    scwin.f_enableSetting();
  } else if (chkWrkClsCd == '05') {
    // 해지를 선택 하는 경우 보험기간, 해지사유만 수정 가능           
    //$c.gus.cfEnableObjects([ed_carInsuranceShortStdDt, ed_carInsuranceShortEndDt, img_carInsuranceShortStdDt, img_carInsuranceShortEndDt]);
    $c.gus.cfEnableObjects($p, [lc_cancelCd, udc_carInsuranceYear]);
    //$c.gus.cfEnableObjects([ed_luggageInsuranceShortStdDt, ed_luggageInsuranceShortEndDt, img_luggageInsuranceShortStdDt, img_luggageInsuranceShortEndDt]);
    $c.gus.cfEnableObjects($p, [udc_luggageInsuranceYear]);
  }
  if (ds_vehclInsuranceMgnt.getCellData(row, "apprvStsCd") != '05') {
    $c.gus.cfDisableObjects($p, [rd_wrkClsCd]);
  }
};

//-------------------------------------------------------------------------
// 취소 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
  $c.data.undoRow($p, ds_vehclInsuranceMgnt);
  rd_wrkClsCd.focus();
  scwin.f_firstSetting();
  scwin.f_onloadSetting();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (ed_reqApplyStdDt.getValue() == "" || ed_reqApplyEndDt.getValue() == "") {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "신청일자"));
    ed_reqApplyStdDt.focus();
    return;
  }

  //시작일자가 종료일자 이전인지 check
  if (!$c.gus.cfIsAfterDate($p, ed_reqApplyStdDt.getValue(), ed_reqApplyEndDt.getValue())) {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_039));
    return;
  }
  $c.sbm.execute($p, sbm_search);

  //scwin.f_setFileUpDownFrame(slipNo);
};

//-------------------------------------------------------------------------
// 공통코드 조회 - 전 (past)
//-------------------------------------------------------------------------     
scwin.f_cdNm = async function (GRP_CD, CD) {
  let grp_cd = GRP_CD;
  let pCode = CD;

  // SELECT 절 
  let param1 = " CD_NM      as COL1 " + ",''      as COL2 " + ",''      as COL3 " + ",''      as COL4 " + ",''      as COL5 " + ",''      as COL6 " + ",''      as COL7 " + ",''      as COL8 " + ",''      as COL9 " + ",''      as COL10";

  // 대상테이블     
  let param2 = " TB_ZZ002 ";

  // 조건절
  let param3 = " AND GRP_CD = '" + grp_cd + "'" + " AND CD = '" + pCode + "'";
  let param4 = "CD_NM";
  dma_cdNm.set("param1", param1);
  dma_cdNm.set("param2", param2);
  dma_cdNm.set("param3", param3);
  dma_cdNm.set("param4", param4);
  sbm_cdNm.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
  await $c.sbm.execute($p, sbm_cdNm);
};
scwin.check_Num = function (a) {
  let num = a;
  let j;
  let t = false;

  //소수점 유무 판별
  for (j = 1; j <= num.length; j++) {
    if (num.substring(j - 1, j) == '.') {
      t = true; //소수점 있음
    }
  }

  //소수점 몇 자리인지 판별
  if (t == true) {
    num = (num = num.toString()).substring(num.indexOf('.') + 1, num.length);
    if (num.length > 1) {
      //소수점 2자리 이상
      return false;
    } else {
      //소수점 1자리 이하
      return true;
    }
  } else {
    //소수점 없음
    return true;
  }
};

